  5	/**
  6	 * Core event bus — pub/sub backbone of the system.
  7	 * 8 public methods: on, off, emit, once, getListenerCount, getEventNames, removeAllListeners, waitFor
  8	 */
  9	export class EventBus {
 10	  private handlers: Map<string, Set<EventHandler>> = new Map();
 11	  private config: EventConfig;
 12	
 13	  constructor(config: Partial<EventConfig> = {}) {
 14	    this.config = { ...DEFAULT_CONFIG, ...config };
 15	  }
 16	
 17	  /** Subscribe to an event */
 18	  on(eventName: string, handler: EventHandler): void {
 19	    validateEventName(eventName);
 20	    if (!this.handlers.has(eventName)) {
 21	      this.handlers.set(eventName, new Set());
 22	    }
 23	    const handlers = this.handlers.get(eventName)!;
 24	    if (handlers.size >= this.config.maxListenersPerEvent) {
 25	      throw new Error(`Max listeners (${this.config.maxListenersPerEvent}) reached for event: ${eventName}`);
 26	    }
 27	    handlers.add(handler);
 28	  }
 29	
 30	  /** Unsubscribe from an event */
 31	  off(eventName: string, handler: EventHandler): void {
 32	    const handlers = this.handlers.get(eventName);
 33	    if (handlers) {
 34	      handlers.delete(handler);
 35	      if (handlers.size === 0) this.handlers.delete(eventName);
 36	    }
 37	  }
 38	
 39	  /** Emit an event to all subscribers */
 40	  emit(eventName: string, payload: EventPayload): void {
 41	    validateEventName(eventName);
 42	    const handlers = this.handlers.get(eventName);
 43	    if (!handlers) return;
 44	    const eventId = generateEventId();
 45	    const enrichedPayload: EventPayload = {
 46	      ...payload,
 47	      _meta: { eventId, timestamp: Date.now(), eventName },
 48	    };
 49	    for (const handler of handlers) {
 50	      try {
 51	        handler(enrichedPayload);
 52	      } catch (err) {
 53	        if (this.config.throwOnHandlerError) throw err;
 54	        console.error(`[EventBus] Handler error for ${eventName}:`, err);
 55	      }
 56	    }
 57	  }
 58	
 59	  /** Subscribe to an event, auto-unsubscribe after first invocation */
 60	  once(eventName: string, handler: EventHandler): void {
 61	    const wrapper: EventHandler = (payload) => {
 62	      this.off(eventName, wrapper);
 63	      handler(payload);
 64	    };
 65	    this.on(eventName, wrapper);
 66	  }
 67	
 68	  /** Get the count of listeners for a specific event */
 69	  getListenerCount(eventName: string): number {
 70	    return this.handlers.get(eventName)?.size ?? 0;
 71	  }
 72	
 73	  /** Get all event names that have active listeners */
 74	  getEventNames(): string[] {
 75	    return [...this.handlers.keys()];
 76	  }
 77	
 78	  /** Remove all listeners, optionally for a specific event */
 79	  removeAllListeners(eventName?: string): void {
 80	    if (eventName) {
 81	      this.handlers.delete(eventName);
 82	    } else {
 83	      this.handlers.clear();
 84	    }
 85	  }
 86	
 87	  /** Wait for an event to be emitted (promise-based) */
 88	  waitFor(eventName: string, timeoutMs?: number): Promise<EventPayload> {
 89	    return new Promise((resolve, reject) => {
 90	      const timeout = timeoutMs ?? this.config.defaultTimeoutMs;
 91	      let timer: ReturnType<typeof setTimeout> | undefined;
 92	
 93	      if (timeout > 0) {
 94	        timer = setTimeout(() => {
 95	          this.off(eventName, handler);
 96	          reject(new Error(`Timeout waiting for event: ${eventName}`));
 97	        }, timeout);
 98	      }
 99	
100	      const handler: EventHandler = (payload) => {
101	        if (timer) clearTimeout(timer);
102	        this.off(eventName, handler);
103	        resolve(payload);
104	      };
105	      this.on(eventName, handler);
106	    });
107	  }
108	}
