123	  record(eventNames: string[]): void {
124	    for (const name of eventNames) {
125	      this.bus.on(name, (payload) => {
126	        this.events.push({ eventName: name, payload, storedAt: Date.now() });
127	        if (this.events.length > this.maxSize) {
128	          this.events.shift();
129	        }
130	      });
131	    }
132	  }
133	
134	  /** Replay stored events through the bus */
135	  replay(filter?: EventFilter): void {
136	    const toReplay = filter
137	      ? this.events.filter((e) => filter(e.eventName, e.payload))
138	      : this.events;
139	    for (const event of toReplay) {
140	      this.bus.emit(event.eventName, event.payload);
141	    }
142	  }
143	
144	  /** Get stored event count */
145	  getCount(): number {
146	    return this.events.length;
147	  }
148	
149	  /** Clear all stored events */
150	  clear(): void {
151	    this.events = [];
152	  }
153	}
